  row.className = 'ticket-row';
  row.setAttribute('aria-keyshortcuts', 'Control+Enter');

  const title = document.createElement('span');
  title.className = 'ticket-row-title';
  title.textContent = 'Ticket #' + nextTicketAfter + ' - Billing issue';

