after.js:
let zoomLevel = 1;

function zoomIn() {
  zoomLevel = Math.min(zoomLevel + 0.2, 3);
  updateZoom();
}

function zoomOut() {
  zoomLevel = Math.max(zoomLevel - 0.2, 0.5);
  updateZoom();
}

function resetZoom() {
  zoomLevel = 1;
  updateZoom();
}

function updateZoom() {
  const mapImage = document.getElementById('mapImage');
  mapImage.style.transform = `scale(${zoomLevel})`;
  mapImage.style.transformOrigin = 'center';
}

